import { useState, useMemo, useCallback, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Layers } from 'lucide-react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import Toolbar from '@/sections/Toolbar';
import SiteCardGrid from '@/sections/SiteCardGrid';
import AddSiteForm from '@/sections/AddSiteForm';
import ManageCategoriesDialog from '@/sections/ManageCategoriesDialog';
import type { Site } from '@/types/site';

const STORAGE_KEY = 'inspirationSites';

const defaultSites: Site[] = [
  {
    id: 1779955032555,
    name: "Design Prompts",
    url: "https://www.designprompts.dev/",
    description: "多个明确和另类的网站风格参考。并且可以提取Prompt",
    category: "网站审美",
    screenshotBase64: "data:image/png;base64,",
    createdAt: 1779955032555,
    isFavorite: false
  },
  {
    id: 1779949454201,
    name: "Pinterest",
    url: "https://www.pinterest.com",
    description: "（UI、插画、摄影等设计灵感）全球视觉收集站（国外版“小红书”）",
    category: "设计资源",
    screenshotBase64: "data:image/png;base64,",
    createdAt: 1779949454201,
    isFavorite: true
  },
  {
    id: 1779949457201,
    name: "Figma",
    url: "https://www.figma.com",
    description: "网站、组件的设计参考。并且可以导出版面CCS喂给AI",
    category: "网站审美",
    screenshotBase64: "data:image/png;base64,",
    createdAt: 1779949457201,
    isFavorite: false
  }
];

function loadSites(): Site[] {
  // Always use defaultSites from code (latest data)
  // Clear old localStorage to avoid stale data
  localStorage.removeItem(STORAGE_KEY);
  return defaultSites;
}

function saveSites(sites: Site[]) { localStorage.setItem(STORAGE_KEY, JSON.stringify(sites)); }

export default function App() {
  const [sites, setSites] = useState<Site[]>(loadSites);
  const [editingSite, setEditingSite] = useState<Site | null>(null);
  const [activeCategory, setActiveCategory] = useState('all');
  const [keyword, setKeyword] = useState('');
  const [dialogOpen, setDialogOpen] = useState(false);
  const [catDialogOpen, setCatDialogOpen] = useState(false);

  useEffect(() => { saveSites(sites); }, [sites]);

  const categories = useMemo(() => {
    const cats = new Set<string>();
    sites.forEach((s) => { if (s.category) cats.add(s.category); });
    return Array.from(cats).sort();
  }, [sites]);

  const siteCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    sites.forEach((s) => { if (s.category) counts[s.category] = (counts[s.category] || 0) + 1; });
    return counts;
  }, [sites]);

  const filteredSites = useMemo(() => {
    let filtered = sites.filter((site) => {
      if (activeCategory !== 'all' && site.category !== activeCategory) return false;
      if (keyword.trim()) {
        const kw = keyword.trim().toLowerCase();
        return site.name.toLowerCase().includes(kw) || site.description.toLowerCase().includes(kw) || site.category.toLowerCase().includes(kw);
      }
      return true;
    });
    filtered.sort((a, b) => b.createdAt - a.createdAt);
    return filtered;
  }, [sites, activeCategory, keyword]);

  const handleSave = useCallback((data: Omit<Site, 'id' | 'createdAt'>, screenshotFile?: File | null) => {
    const doSave = (base64: string) => {
      if (editingSite) {
        setSites((prev) => prev.map((s) => s.id === editingSite.id
          ? { ...s, name: data.name, url: data.url, description: data.description, category: data.category, isFavorite: data.isFavorite, screenshotBase64: base64 || s.screenshotBase64 }
          : s));
        setEditingSite(null);
      } else {
        setSites((prev) => [{
          id: Date.now(), name: data.name, url: data.url, description: data.description,
          category: data.category, screenshotBase64: base64 || '',
          createdAt: Date.now(), isFavorite: false,
        }, ...prev]);
      }
      setDialogOpen(false);
    };
    // If user uploaded a new screenshot file, convert to base64
    if (screenshotFile) {
      const reader = new FileReader();
      reader.onload = (e) => doSave(e.target?.result as string);
      reader.readAsDataURL(screenshotFile);
    } else {
      // Use existing screenshot (from editing) or empty
      doSave(data.screenshotBase64 || '');
    }
  }, [editingSite]);

  const handleDelete = useCallback((id: number) => {
    setSites((prev) => prev.filter((s) => s.id !== id));
    if (editingSite?.id === id) setEditingSite(null);
  }, [editingSite]);

  const handleEdit = useCallback((site: Site) => {
    setEditingSite(site);
    setDialogOpen(true);
  }, []);

  const handleToggleFavorite = useCallback((id: number) => {
    setSites((prev) => prev.map((s) => s.id === id ? { ...s, isFavorite: !s.isFavorite } : s));
  }, []);

  const handleRenameCategory = useCallback((oldName: string, newName: string) => {
    setSites((prev) => prev.map((s) => s.category === oldName ? { ...s, category: newName } : s));
    if (activeCategory === oldName) setActiveCategory('all');
  }, [activeCategory]);

  const handleDeleteCategory = useCallback((category: string, moveTo?: string) => {
    setSites((prev) => prev.map((s) => s.category === category ? { ...s, category: moveTo || '' } : s));
    if (activeCategory === category) setActiveCategory('all');
  }, [activeCategory]);

  const handleOpenAdd = () => { setEditingSite(null); setDialogOpen(true); };
  const handleCloseDialog = () => { setDialogOpen(false); setEditingSite(null); };

  const handleExport = useCallback(() => {
    const dataStr = JSON.stringify(sites, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `inspiration-sites-${new Date().toISOString().slice(0, 19)}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [sites]);

  const headerIconShadow = { background: '#F0F0F3', boxShadow: '-4px -4px 8px #FFFFFF, 4px 4px 8px rgba(174, 174, 192, 0.4)' };
  const dialogShadow = { background: '#F0F0F3', boxShadow: '-8px -8px 20px #FFFFFF, 8px 8px 20px rgba(174, 174, 192, 0.45)' };

  return (
    <div className="min-h-screen" style={{ backgroundColor: '#F0F0F3' }}>
      <div className="max-w-[1400px] mx-auto px-4 md:px-8 py-8 md:py-12 pb-20">
        {/* Header */}
        <motion.header initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.4 }} className="text-center mb-10">
          <div className="flex items-center justify-center gap-3 mb-3">
            <div className="w-12 h-12 rounded-2xl flex items-center justify-center" style={headerIconShadow}>
              <Layers className="w-6 h-6" style={{ color: '#745FF2' }} />
            </div>
            <h1 className="text-3xl md:text-4xl font-semibold tracking-tight text-gradient-neu">Inspiration-website</h1>
          </div>
          <p className="text-sm md:text-base mt-2" style={{ color: '#808B9F' }}>设计 · AI · 创意工具库 — 收藏属于你的灵感世界</p>
        </motion.header>

        {/* Toolbar */}
        <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.4, delay: 0.1 }} className="mb-6">
          <Toolbar
            categories={categories}
            activeCategory={activeCategory}
            onCategoryChange={setActiveCategory}
            onSearch={setKeyword}
            onAdd={handleOpenAdd}
            onExport={handleExport}
          />
        </motion.div>

        {/* Stats */}
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.4, delay: 0.15 }} className="flex items-center gap-4 mb-5 px-1">
          <span className="text-sm" style={{ color: '#94A3B8' }}>
            共 <span className="font-medium" style={{ color: '#728AB7' }}>{sites.length}</span> 个网站
          </span>
          {activeCategory !== 'all' && (
            <span className="text-sm" style={{ color: '#94A3B8' }}>
              筛选后 <span className="font-medium" style={{ color: '#728AB7' }}>{filteredSites.length}</span> 个
            </span>
          )}
          {keyword && (
            <span className="text-sm" style={{ color: '#94A3B8' }}>
              搜索 <span className="font-medium" style={{ color: '#728AB7' }}>&quot;{keyword}&quot;</span>
            </span>
          )}
        </motion.div>

        {/* Cards Grid */}
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.4, delay: 0.2 }}>
          <SiteCardGrid sites={filteredSites} onEdit={handleEdit} onDelete={handleDelete} onToggleFavorite={handleToggleFavorite} />
        </motion.div>
      </div>

      {/* Add/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={(open) => { if (!open) handleCloseDialog(); }}>
        <DialogContent className="sm:max-w-lg rounded-3xl border-none" style={dialogShadow}>
          <DialogHeader>
            <DialogTitle className="text-xl font-semibold text-center" style={{ color: '#728AB7' }}>
              {editingSite ? '✏️ 编辑网站' : '➕ 添加新网站'}
            </DialogTitle>
          </DialogHeader>
          <AddSiteForm
            editingSite={editingSite}
            existingCategories={categories}
            onSave={handleSave}
            onCancel={handleCloseDialog}
          />
        </DialogContent>
      </Dialog>

      {/* Manage Categories Dialog */}
      <ManageCategoriesDialog
        open={catDialogOpen}
        onClose={() => setCatDialogOpen(false)}
        categories={categories}
        siteCounts={siteCounts}
        onRename={handleRenameCategory}
        onDelete={handleDeleteCategory}
      />
    </div>
  );
}
